#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAXN 100005
#define MAXL 105
#define HASH 200003

typedef struct Node {
    char key[MAXL];
    int group;
    struct Node* next;
} Node;

Node* table[HASH];

char words[MAXN][MAXL];
int group_size[MAXN];
int group_words[MAXN][10]; // temporary small, will convert to dynamic

// Instead use linked list of indices per group
typedef struct GNode {
    int idx;
    struct GNode* next;
} GNode;

GNode* group_head[MAXN];
GNode* group_tail[MAXN];

int gcount=0;

unsigned long long hash_str(char *s){
    unsigned long long h=1469598103934665603ULL;
    while(*s){
        h^=*s++;
        h*=1099511628211ULL;
    }
    return h;
}

int cmp_char(const void *a,const void *b){
    return (*(char*)a)-(*(char*)b);
}

int find_or_create(char *key){
    unsigned long long h = hash_str(key)%HASH;
    Node* cur = table[h];

    while(cur){
        if(strcmp(cur->key,key)==0)
            return cur->group;
        cur=cur->next;
    }

    Node* node=(Node*)malloc(sizeof(Node));
    strcpy(node->key,key);
    node->group=gcount;
    node->next=table[h];
    table[h]=node;

    return gcount++;
}

void add_to_group(int gid,int idx){
    GNode* node=(GNode*)malloc(sizeof(GNode));
    node->idx=idx;
    node->next=NULL;

    if(!group_head[gid]){
        group_head[gid]=group_tail[gid]=node;
    }else{
        group_tail[gid]->next=node;
        group_tail[gid]=node;
    }
}

int main(){
    int n;
    scanf("%d",&n);

    for(int i=0;i<n;i++){
        scanf("%s",words[i]);

        char key[MAXL];
        strcpy(key,words[i]);
        qsort(key,strlen(key),sizeof(char),cmp_char);

        int gid=find_or_create(key);
        add_to_group(gid,i);
    }

    // print groups in first appearance order
    for(int g=0; g<gcount; g++){
        GNode* cur=group_head[g];
        int first=1;
        while(cur){
            if(!first) printf(" ");
            printf("%s",words[cur->idx]);
            first=0;
            cur=cur->next;
        }
        printf("\n");
    }
}

